values
  ('584', '노른자크림 육회샐러드', '반찬', '소고기(홍두깨살, 150g), 두릅(100g), 아보카도(1/2개),
배(1/4개), 마늘(20g), 달걀(1개), 레몬(1/8개), 크림치즈(20g),
설탕(20g), 소금(0.3g), 참기름(5g)', '["소고기","두릅","아보카도","배","마늘","달걀","레몬","크림치즈","설탕","소금","참기름"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','e820dd18-6cf5-4919-b61f-51b691c8c407','906bfef3-a41b-40d3-acda-7d8f23d2bcd2','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','fc6e31ce-388e-45cd-956b-b238b9134eb1','c7d438a6-34d6-423f-905d-446b839e2f39','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','b42c6eac-0afb-4d87-8942-ed1a9c294b09','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"소고기는 홍두깨살로 준비해서\r\n0.3mm 두께로 썰고, 배는 껍질을 벗겨\r\n채 썰어 설탕을 뿌린다.","imageUrl":null},{"step":2,"text":"끓는 물에 소금을 넣고 두릅을 데친 후\r\n찬물에 헹구어 건진다.","imageUrl":null},{"step":3,"text":"소금과 설탕, 다진 마늘을 넣고 소고기\r\n육회 양념장을 만든다.","imageUrl":null},{"step":4,"text":"삶은 달걀노른자와 크림치즈, 레몬을\r\n섞어 짤주머니에 담는다.","imageUrl":null},{"step":5,"text":"숙성이 잘된 아보카도는 강판에 갈아\r\n준비한다.","imageUrl":null},{"step":6,"text":"접시에 양념한 육회와 두릅을 담고 그\r\n위에 배를 올리고, 달걀크림과\r\n아보카도를 짜서 올린다","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00584_2.png', 177.4, 10, 25.3, 4, 245.6),
  ('585', '닭고기 완자삼계죽', '일품', '닭고기(1마리), 인삼(1뿌리), 찹쌀(50g), 대추(10알), 마늘(30g),
대파(30g), 양파(30g), 통후추(10알), 저염간장(10g)', '["닭고기","인삼","찹쌀","대추","마늘","대파","양파","통후추","저염간장"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','9f4dacdc-b7a6-43f9-ab9b-6a3b28042318','a5bc0b46-0192-496a-b429-d2cb90b2bca9','b371c5d2-f12b-47ee-9a87-26efd09db09d','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"닭은 깨끗이 씻고 포를 뜬다.","imageUrl":null},{"step":2,"text":"닭고기는 15분 정도 삶아 식으면 곱게\r\n다져 다진 마늘, 대파, 저염간장을 넣고\r\n완자를 만든다.","imageUrl":null},{"step":3,"text":"인삼은 뇌두를 제거하고 깨끗이\r\n씻는다.","imageUrl":null},{"step":4,"text":"찹쌀은 약 30분 정도 충분히 불린다","imageUrl":null},{"step":5,"text":"대추는 소금물에 깨끗이 씻고 씨를\r\n제거한다.","imageUrl":null},{"step":6,"text":"믹서에 인삼과 대추, 불린 찹쌀, 물을\r\n정도 넣고 곱게 간 뒤, 냄비에 담아 죽을\r\n쑤다가 다 익으면 만들어 놓은 완자를\r\n넣고 한소끔 더 끓인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00585_2.png', 150.4, 26.2, 9.9, 0.7, 51.9),
  ('586', '대하마늘볶음밥', '밥', ' 대하(3마리), 쌀(90g), 당근(20g), 깻잎(2장), 양파(30g), 숙주(50g), 대추(2알), 청고추(1개), 파(10g), 마늘(10g), 생강(5g), 식용유(5g)
, 저염간장(5g)', '["대하","쌀","당근","깻잎","양파","숙주","대추","청고추","파","마늘","생강","식용유","저염간장"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','e38c12a7-43cb-421a-a36e-7ef0d32517fa','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','2647e451-e8f5-4fce-91bd-8beabb2384d8','b371c5d2-f12b-47ee-9a87-26efd09db09d','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','a7a59e81-de3d-4893-b56a-b2218732a25b','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"새우는 내장을 제거하고 껍질을 벗겨 깨끗이 씻는다.","imageUrl":null},{"step":2,"text":"찜기에 새우와 생강을 넣어 약 5분 정도 찐다.","imageUrl":null},{"step":3,"text":"마늘은 납작 썰고, 당근과 양파, 파, 깻잎, 청고추, 대추는 굵게 다진다.","imageUrl":null},{"step":4,"text":"숙주는 꼬리를 떼어 다듬고, 끓는 물에 살짝 데친다.","imageUrl":null},{"step":5,"text":"팬에 식용유를 두른 뒤 손질한 채소를 넣어 볶는다.","imageUrl":null},{"step":6,"text":"밥과 새우를 넣어 볶고, 저염간장을 넣어 볶아 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309012647_1678336007930.jpg', 286.6, 32.5, 14, 11.2, 191.4),
  ('587', '두부 카프리제', '반찬', '소고기(100g), 돼지고기(100g), 표고버섯(2개), 마(100g),
연근(20g), 감자(60g), 깻잎(3장), 애호박(1/3개), 마늘(20g),
두유(100g), 설탕(20g), 소금(0.2g), 저염간장(20g)', '["소고기","돼지고기","표고버섯","마","연근","감자","깻잎","애호박","마늘","두유","설탕","소금","저염간장"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','70e914d4-0d03-4202-8b66-81bd8499aa08','66458b1b-c92f-43fa-8eba-e428892ce88a','a988ffbb-92c3-4c68-8cea-a2f10c329015','b20f623d-e722-42af-9bd1-7c11b5e15aa6','20894da1-739d-4d52-b5fe-4943bd3492d5','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','fc6e31ce-388e-45cd-956b-b238b9134eb1','a4e9789c-3090-43d8-ab14-e4e168f8b910','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"토마토는 깨끗이 씻어 슬라이스한다.","imageUrl":null},{"step":2,"text":"두부는 원형틀을 이용해서 토마토와\r\n같은 크기로 만들고 소금을 살짝 뿌린\r\n뒤 물기를 제거한다.","imageUrl":null},{"step":3,"text":"팬에 올리브오일을 두르고 두부를 살짝\r\n굽는다.","imageUrl":null},{"step":4,"text":"어린잎은 찬물에 담근다.","imageUrl":null},{"step":5,"text":"발사믹소스에 설탕과 레몬즙을 넣고\r\n골고루 섞어 소스를 만든다.","imageUrl":null},{"step":6,"text":"두부와 준비한 토마토를 접시에 돌려\r\n담고 어린잎을 위에 올린 뒤 먹기\r\n직전에 발사믹소스와 파마산치즈를\r\n뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00587_2.png', 140.2, 6.8, 11.1, 7.6, 229.6),
  ('217', '미역볶음밥', '밥', ' 쌀(80g), 완두콩(10g), 닭고기(100g), 대추(10g), 수삼(20g)
양파(20g), 당근(10g),강황가루(3g), 맛술(15g)', '["쌀","완두콩","닭고기","대추","수삼","양파","당근","강황가루","맛술"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','5fd34bed-4339-4fcc-9221-f082ce6ac652','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','b371c5d2-f12b-47ee-9a87-26efd09db09d','9f4dacdc-b7a6-43f9-ab9b-6a3b28042318','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','a7cf6fb8-b34f-4cfe-a4af-d8e000090dcb','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1']::uuid[], '[{"step":1,"text":"쌀과 다시마를 넣고 쌀과 동량의\r\n물을 부어 밥을 고슬고슬하게\r\n짓는다.","imageUrl":null},{"step":2,"text":"양파는 굵게 다지고, 쪽파와 고추는\r\n송송 썰고, 오징어와 주꾸미는 먹기\r\n좋은 크기로 썬다.","imageUrl":null},{"step":3,"text":"달군 팬에 들기름을 두르고 다진\r\n마늘을 볶아 향을 낸다.","imageUrl":null},{"step":4,"text":"미역을 넣고 볶다가 손질해둔\r\n오징어, 주꾸미, 새우살, 양파를 넣어\r\n볶는다.","imageUrl":null},{"step":5,"text":"밥을 넣고 소금을 넣어 볶다가\r\n들깻가루를 넣어 볶는다.","imageUrl":null},{"step":6,"text":"송송 썬 쪽파와 청양고추, 붉은\r\n고추를 넣어 조금 더 볶아\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00217_2.png', 515.2, 25.5, 5.85, 5.43, 488.5),
  ('218', '청국장볶음밥', '밥', ' 쌀(100g), 현미(30g), 감자(30g), 고구마(15g), 양파(15g), 연근(15g)
당근(15g), 애호박(15g), 우엉(15g), 마늘(3g), 시금치(5g), 참나물(10g)
깻잎(5g), 미나리(5g),다시마(2g),생청국장(30g), 들깻가루(2g), 올리브유(10g), 들기름(8g)', '["쌀","현미","감자","고구마","양파","연근","당근","애호박","우엉","마늘","시금치","참나물","깻잎","미나리","다시마","생청국장","들깻가루","올리브유","들기름"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','20894da1-739d-4d52-b5fe-4943bd3492d5','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','b20f623d-e722-42af-9bd1-7c11b5e15aa6','e38c12a7-43cb-421a-a36e-7ef0d32517fa','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','6b3a8bca-adc3-48f5-813b-6b06630e11dd','fc6e31ce-388e-45cd-956b-b238b9134eb1','9a7f4da6-531b-4478-89ff-d73beafcad1b','09065cd3-28cc-4a82-8b3e-5121054c7482','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','dc7b2b73-74de-4fb8-9274-a5967ca444f9','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','184687ba-0cba-4fec-bb21-33fe300c2073','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','f5534afd-2a26-4493-8ec1-fd680dcb3bef']::uuid[], '[{"step":1,"text":"쌀과 현미는 물에 깨끗이 씻어 불린\r\n후 밥을 고슬고슬하게 짓는다.","imageUrl":null},{"step":2,"text":"감자, 고구마, 우엉, 양파, 당근,\r\n애호박, 연근은 작게 깍둑 썰고,\r\n마늘은 편 썬다.","imageUrl":null},{"step":3,"text":"시금치와 참나물, 깻잎은 굵게 채\r\n썰고, 미나리는 2.5㎝ 길이로 썬다.","imageUrl":null},{"step":4,"text":"물(50g)에 다시마를 우려내 육수를\r\n내고 청국장을 넣어 잘 푼 뒤\r\n들깻가루를 넣고 잘 저어주며 졸여\r\n청국장소스를 만든다.","imageUrl":null},{"step":5,"text":"팬에 올리브유와 들기름을 두르고\r\n양파, 마늘을 약한 불에 볶다가\r\n감자, 고구마, 우엉, 연근, 당근,\r\n애호박을 넣고 같이 볶는다.","imageUrl":null},{"step":6,"text":"밥과 청국장소스를 부어 80% 정도\r\n볶다가 시금치, 참나물, 미나리를\r\n넣고 한 번 더 볶고 채 썬 깻잎을\r\n올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00218_2.png', 467.9, 25.05, 4.27, 4.9, 234.1),
  ('219', '해물볶음밥', '밥', '볶음밥 쌀(100g), 아스파라거스(5g), 새송이버섯(10g), 달걀(40g)
문어(20g), 새우살(20g), 주꾸미(15g)
미나리볶음고추장 무(20g), 우엉(10g), 미나리(5g),', '["볶음밥 쌀","아스파라거스","새송이버섯","달걀","문어","새우살","주꾸미","미나리볶음고추장 무","우엉","미나리"]'::jsonb, ARRAY['a8462d27-4ef1-4919-ae9b-10c8f8b9545f','3f94371a-728f-49ae-8ea9-1a1e87b68048','c7d438a6-34d6-423f-905d-446b839e2f39','55a34ec2-28ee-407c-8ad5-7462cbe99d55','6f10b4ad-53a2-4a07-ba89-19a6b074373d','c3f77c6a-2dd2-4592-875f-0aa74771d6d0','6b3a8bca-adc3-48f5-813b-6b06630e11dd','dc7b2b73-74de-4fb8-9274-a5967ca444f9']::uuid[], '[{"step":1,"text":"쌀은 씻어서 체에 건져 1시간 이상\r\n불린 후 동량의 물을 부어 밥을\r\n짓는다.","imageUrl":null},{"step":2,"text":"아스파라거스, 새송이버섯은 작게\r\n깍둑 썰고, 무와 우엉, 미나리는\r\n다진다.","imageUrl":null},{"step":3,"text":"식용유(10g)를 두른 팬을 중간 불로\r\n달궈 달걀을 넣고 스크램블로\r\n볶는다.","imageUrl":null},{"step":4,"text":"문어, 새우살, 주꾸미는 끓는 물에\r\n살짝 데쳐 작게 자른다.","imageUrl":null},{"step":5,"text":"식용유(15g)를 두른 팬을 중간 불로\r\n달궈 밥을 넣어 볶다가 문어, 새우살,\r\n주꾸미, 스크램블 에그를 넣고 조금\r\n더 볶는다.","imageUrl":null},{"step":6,"text":"무와 우엉에 고추장과 참기름,\r\n물(40g)을 넣고 묽게 졸인 후 불을\r\n끄고 미나리를 넣고 섞어\r\n미나리볶음고추장을 만들어 밥에\r\n곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00219_2.png', 493.2, 26.9, 7.28, 2.99, 681.9),
  ('220', '토마토카레 채소볶음밥', '밥', ' 감자(20g), 양파(10g), 당근(10g), 피망(5g), 닭가슴살(20g)
밥(200g), 브로콜리(10g), 방울토마토(20g), 플레인 요구르트(15g),후춧가루(0.1g), 토마토페이스트(20g), 파프리카가루(3g), 카레가루(15g)', '["감자","양파","당근","피망","닭가슴살","밥","브로콜리","방울토마토","플레인 요구르트","후춧가루","토마토페이스트","파프리카가루","카레가루"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','df459e6f-3515-45d5-8c9a-9d37b6249379','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','ecb35816-34ae-4c4c-867a-e3f84db92755','9bf64924-ce53-42bb-849e-7294416e95d6','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','bb41a88a-ea2b-4830-876d-91fe7f640296','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','76e95535-f965-4685-a7a6-55ae26aa202c','5e79d288-1400-4817-bd20-e5e6041821b1','495b9f1e-aa3b-4506-9bb8-feb0a493901e']::uuid[], '[{"step":1,"text":"감자, 양파, 당근, 피망은 볶음밥에\r\n넣을 분량은 잘게 다지고, 카레에\r\n넣을 분량은 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"닭가슴살도 한입 크기로 잘라\r\n후춧가루로 밑간한다.","imageUrl":null},{"step":3,"text":"팬에 식용유(15g)를 두른 뒤 잘게\r\n다진 감자, 양파, 당근, 피망을 넣고\r\n볶다가 밥을 넣고 같이 볶는다.","imageUrl":null},{"step":4,"text":"식용유(15g)를 두른 팬에 닭고기를\r\n먼저 볶다가 한입 크기로 썬 감자,\r\n당근, 양파, 피망, 브로콜리를 넣고\r\n볶은 뒤 마지막에 방울토마토를\r\n넣는다.","imageUrl":null},{"step":5,"text":"토마토페이스트을 넣고 볶다가\r\n파프리카가루를 넣어 향을 낸다.","imageUrl":null},{"step":6,"text":"카레가루를 푼 물(300g)을 부어\r\n끓이다가 플레인 요구르트를 넣고\r\n농도를 맞춘 뒤 밥 위에 얹어\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00220_2.png', 612.1, 24.5, 3.52, 4.46, 435.2),
  ('221', '구운주먹밥', '밥', ' 현미(100g), 톳(30g), 생김(5g), 달걀(50g),밑간 참기름(4g), 참깨(2g),무침양념 설탕(2g), 식초(2g)', '["현미","톳","생김","달걀","밑간 참기름","참깨","무침양념 설탕","식초"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','f3f07b4b-1a27-4a6d-be6d-09e58352e063','c7d438a6-34d6-423f-905d-446b839e2f39','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"현미로 밥을 지은 뒤 밥 밑간을 넣고\r\n섞는다.","imageUrl":null},{"step":2,"text":"톳에 톳 무침양념을 넣고 버무린다.","imageUrl":null},{"step":3,"text":"밥에 톳을 넣고 버무린다.","imageUrl":null},{"step":4,"text":"밥을 먹기 좋은 크기로 둥글게 뭉친\r\n뒤 부순 생김을 골고루 묻힌다.","imageUrl":null},{"step":5,"text":"주먹밥에 달걀물을 입힌 뒤 팬에\r\n구워 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00221_2.png', 335.1, 35.43, 5.79, 6.84, 79.4),
  ('222', '깐풍주먹밥', '밥', ' 칵테일새우(10g), 다진 쇠고기(15g), 후춧가루(1g), 참기름(7g)
찹쌀현미밥(200g), 밀가루(30g), 파인애플(10g), 부추(10g),다진 마늘(4g), 다진 붉은 고추(7g), 다진 풋고추(7g), 식초(10g)
함초가루(10g), 설탕(15g)', '["칵테일새우","다진 쇠고기","후춧가루","참기름","찹쌀현미밥","밀가루","파인애플","부추","다진 마늘","다진 붉은 고추","다진 풋고추","식초","함초가루","설탕"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','1c49d1f4-5781-474d-818d-bd7002a4dc0b','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','0c0ade94-cfd8-4104-b44c-40e942cac482','aab3b0b9-d346-4697-a1c8-1b1530153788','c97290bd-7146-45bc-8e7f-28390e7a95b0','058648c3-fd8e-476d-952f-b15dc67f1877','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','6c285c60-022a-4a00-b172-87df97f16a2f','2753a03c-9508-458a-9f55-75307de4f7d5','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"칵테일새우는 잘게 다진다.","imageUrl":null},{"step":2,"text":"다진 쇠고기에 후춧가루와\r\n참기름(3g)으로 밑간한 후 볶는다.","imageUrl":null},{"step":3,"text":"찹쌀현미밥에 참기름(4g)을 넣어\r\n밑간하고 식힌 후 새우와 쇠고기를\r\n넣어 뭉쳐준다.","imageUrl":null},{"step":4,"text":"마늘과 고추는 볶다가 식초와\r\n함초가루, 설탕, 물(30g)을 넣고 졸여\r\n소스를 만든다.","imageUrl":null},{"step":5,"text":"밀가루는 반죽한 뒤 얇게 밀어\r\n삼각형으로 잘라 튀긴 후 기름을\r\n뺀다.","imageUrl":null},{"step":6,"text":"위에 주먹밥을 올리고 파인애플을\r\n올린 후 소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00222_2.png', 536.3, 37.6, 7.15, 7.44, 111),
  ('223', '닭봉주먹밥', '밥', ' 닭봉(80g), 우유(20g), 단호박(10g), 새송이버섯(5g), 가지(15g), 주키니호박(15g)
당근(15g), 양파(10g), 시래기(20g), 치즈(20g), 밥(150g), 새싹채소(10g),후춧가루(3g), 참기름(20g), 간장(5g),레몬즙(5g), 마요네즈(12g), 꿀(5g), 부순 참깨(2g)', '["닭봉","우유","단호박","새송이버섯","가지","주키니호박","당근","양파","시래기","치즈","밥","새싹채소","후춧가루","참기름","간장","레몬즙","마요네즈","꿀","부순 참깨"]'::jsonb, ARRAY['e937397f-54e2-49df-997a-f393c58360be','98d652af-a6d6-440c-9653-e22fc5d47d88','3f94371a-728f-49ae-8ea9-1a1e87b68048','3e12cf79-2cde-4309-9f7c-4eccce3fde28','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','ecb35816-34ae-4c4c-867a-e3f84db92755','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','0c0ade94-cfd8-4104-b44c-40e942cac482','f175019d-5a93-4cd4-aabc-e7e79445f15a','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','549c7365-28e9-491f-9040-412558f93a5c','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"닭봉은 손질한 뒤 후춧가루를\r\n섞은 우유에 담가두었다가 구워\r\n준비한다.","imageUrl":null},{"step":2,"text":"단호박, 새송이버섯은 구워서\r\n준비한다.","imageUrl":null},{"step":3,"text":"소스를 만든다.","imageUrl":null},{"step":4,"text":"가지, 주키니호박, 당근, 양파,\r\n시래기는 잘게 다진 뒤 볶는다.","imageUrl":null},{"step":5,"text":"볶은 채소와 치즈를 참기름, 간장과\r\n함께 밥에 넣고 섞는다.","imageUrl":null},{"step":6,"text":"구운 닭봉을 밥으로 감싼 뒤 구운\r\n단호박, 새송이버섯, 새싹채소와\r\n함께 담아 소스를 곁들여\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00223_2.png', 553.4, 20.5, 7.12, 6.08, 454.1),
  ('224', '봄주먹밥', '밥', ' 봄동(10g), 깻잎(6g), 낙지 다리(6g), 참기름(3g)
두릅(8g), 올리브유(4g), 미나리(3g),데친 꼬막살(14g), 올리브유(4g), 밥(100g), 참깨(3g),참기름(10g), 다진 양파(14g), 다진 당근(14g),애호박(14g), 물(150g), 된장(14g)
고춧가루(4g), 다진 마늘(4g), 송송 썬 붉은 고추(4g),썬 청양고추(4g), 으깬 두부(76g)', '["봄동","깻잎","낙지 다리","참기름","두릅","올리브유","미나리","데친 꼬막살","밥","참깨","다진 양파","다진 당근","애호박","물","된장","고춧가루","다진 마늘","송송 썬 붉은 고추","썬 청양고추","으깬 두부"]'::jsonb, ARRAY['3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','0c0ade94-cfd8-4104-b44c-40e942cac482','e820dd18-6cf5-4919-b61f-51b691c8c407','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','dc7b2b73-74de-4fb8-9274-a5967ca444f9','ecb35816-34ae-4c4c-867a-e3f84db92755','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','94786475-832c-4f97-aab7-bf6fbbe2236b','392236b1-82e9-4e38-bd12-6a53b80bf463','84104c49-0af4-4323-a56b-b67002a422d9','fc6e31ce-388e-45cd-956b-b238b9134eb1','4566cac5-9166-4c0d-906a-bfc7360f8f5b']::uuid[], '[{"step":1,"text":"봄동과 깻잎은 데친 뒤 체에 밭쳐\r\n물기를 제거한다.","imageUrl":null},{"step":2,"text":"데친 꼬막살은 물기를 제거하고\r\n다져 올리브유로 양념한 밥에\r\n참깨와 함께 버무린 후 한입 크기로\r\n주먹밥을 만든다.","imageUrl":null},{"step":3,"text":"낙지 다리는 데쳐 찬물에 담가 식힌\r\n뒤 참기름(3g)에 양념하고, 두릅은\r\n데쳐 물기를 제거한 뒤 올리브유로\r\n양념한다.","imageUrl":null},{"step":4,"text":"봄동에 꼬막밥을 넣고 만 뒤\r\n깻잎으로 싸고 데친 미나리로 묶어\r\n봄주먹밥을 만든다.","imageUrl":null},{"step":5,"text":"냄비에 참기름(10g)을 두르고 양파,\r\n당근, 애호박을 넣고 볶은 뒤 물,\r\n된장, 고춧가루, 다진 마늘, 붉은\r\n고추, 청양고추를 넣고 끓이다가\r\n두부를 넣고 조려 두부강된장을\r\n만든다.","imageUrl":null},{"step":6,"text":"봄주먹밥에 낙지와 두릅,\r\n두부강된장을 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00224_2.png', 252.4, 19.63, 4.29, 2.12, 118.1),
  ('225', '깻잎장아찌롤', '밥', ' 쌀(200g), 깻잎장아찌(30g), 김(5g), 새싹(20g),밑간 참기름(5g), 참깨(3g),양파(20g), 피클(20g), 삶은 달걀(60g), 마요네즈(20g),설탕(3g), 물(5g), 머스터드소스(15g)', '["쌀","깻잎장아찌","김","새싹","밑간 참기름","참깨","양파","피클","삶은 달걀","마요네즈","설탕","물","머스터드소스"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','09229cbc-4574-4002-b726-68c37345bbe9','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c7d438a6-34d6-423f-905d-446b839e2f39','549c7365-28e9-491f-9040-412558f93a5c','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"쌀을 씻어 밥을 지은 뒤 밥 밑간을\r\n한다.","imageUrl":null},{"step":2,"text":"양파, 피클, 삶은 달걀은 다진 뒤\r\n마요네즈에 섞어\r\n허브타르타르드레싱을 만든다.","imageUrl":null},{"step":3,"text":"김 위에 양쪽으로 밥을 펴고\r\n허브타르타르드레싱을 위에\r\n올린 후 만다.","imageUrl":null},{"step":4,"text":"깻잎장아찌를 바닥에 깔고 말아놓은\r\n롤을 올린 후 한 번 더 만다.","imageUrl":null},{"step":5,"text":"머스타드소스를 만든다.","imageUrl":null},{"step":6,"text":"한입 크기로 롤을 썬 뒤 새싹과\r\n소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00225_2.png', 375.2, 18.4, 2.6, 3.4, 750.7),
  ('226', '참치비빔밥롤', '밥', ' 멥쌀(60g), 완두콩(30g), 달걀(80g), 주키니호박(15g)
당근(15g), 가지(15g), 참치(25g), 김밥용 김(2g), 케일(3g),후춧가루(3g), 올리브유(5g),식초(3g), 굵게 다진 사과(8g), 로즈마리(2g), 꿀(5g),토마토(50g), 고추(5g)', '["멥쌀","완두콩","달걀","주키니호박","당근","가지","참치","김밥용 김","케일","후춧가루","올리브유","식초","굵게 다진 사과","로즈마리","꿀","토마토","고추"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','5fd34bed-4339-4fcc-9221-f082ce6ac652','c7d438a6-34d6-423f-905d-446b839e2f39','e38c12a7-43cb-421a-a36e-7ef0d32517fa','3e12cf79-2cde-4309-9f7c-4eccce3fde28','770b2134-ddc5-454c-bbd7-8e21c4e96c45','1389717e-81e4-4350-96d4-d627d851aa10','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6c285c60-022a-4a00-b172-87df97f16a2f','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','286d1783-cd34-4aae-ac8b-006529ec8bc5','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"쌀을 물에 불린 뒤 완두콩을 함께\r\n넣고 밥을 짓는다.","imageUrl":null},{"step":2,"text":"달걀을 풀어 체에 내린 뒤 지단을\r\n부치면서 반 정도 익었을 때 그 위에\r\n얇게 썬 주키니호박, 당근, 가지를\r\n올려 익힌다.","imageUrl":null},{"step":3,"text":"참치를 참치밑간에 재운 뒤 겉만\r\n살짝 익힌다.","imageUrl":null},{"step":4,"text":"김에 밥을 올리고, 뒤집어 참치를\r\n올려 만 뒤 그 위에 지단을 올려\r\n한 번 더 만다.","imageUrl":null},{"step":5,"text":"사과드레싱을 만들고,\r\n토마토소스 재료를 간 뒤 체에\r\n거른다.","imageUrl":null},{"step":6,"text":"참치비빔밥롤을 담은 뒤\r\n토마토소스를 곁들이고, 케일에\r\n사과드레싱을 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00226_2.png', 468.1, 19.83, 8.57, 2.72, 171.7),
  ('227', '새싹참치김밥', '밥', ' 파프리카(15g), 파인애플(15g), 달걀(30g), 김(2g), 밥(150g)
새싹채소(10g), 참치(12g),저염간장(5g), 마요네즈(2.5g), 설탕(0.5g)', '["파프리카","파인애플","달걀","김","밥","새싹채소","참치","저염간장","마요네즈","설탕"]'::jsonb, ARRAY['5e79d288-1400-4817-bd20-e5e6041821b1','c97290bd-7146-45bc-8e7f-28390e7a95b0','c7d438a6-34d6-423f-905d-446b839e2f39','09229cbc-4574-4002-b726-68c37345bbe9','ecb35816-34ae-4c4c-867a-e3f84db92755','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','770b2134-ddc5-454c-bbd7-8e21c4e96c45','f175019d-5a93-4cd4-aabc-e7e79445f15a','549c7365-28e9-491f-9040-412558f93a5c','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"소스를 만든다.","imageUrl":null},{"step":2,"text":"파프리카와 파인애플을 먹기 좋게\r\n썬다.","imageUrl":null},{"step":3,"text":"스크램블 에그를 만든다.","imageUrl":null},{"step":4,"text":"김발 위에 ⅔크기로 자른 김을 놓고\r\n밥을 고루 편 뒤 새싹채소,\r\n스크램블 에그, 파프리카, 기름 뺀\r\n참치, 파인애플을 올리고 소스를\r\n고르게 뿌린다.","imageUrl":null},{"step":5,"text":"반으로 접어 먹기 좋게 썰어\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00227_2.png', 319.8, 25.9, 5.78, 2.75, 109.3),
  ('228', '연어주먹밥튀김', '밥', ' 당근(30g), 피망(30g), 양파(30g), 밥(100g), 마요네즈(20g),연어(1캔=130g), 식초(10g), 데리야키소스(15g)
달걀(40g), 빵가루(60g), 어린잎채소(50g),식초(10g), 레몬즙(15g), 간장(10g), 다진 마늘(10g), 꿀(10g)
올리브유(20g), 참깨(5g)', '["당근","피망","양파","밥","마요네즈","연어","식초","데리야키소스","달걀","빵가루","어린잎채소","레몬즙","간장","다진 마늘","꿀","올리브유","참깨"]'::jsonb, ARRAY['e38c12a7-43cb-421a-a36e-7ef0d32517fa','df459e6f-3515-45d5-8c9a-9d37b6249379','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','ecb35816-34ae-4c4c-867a-e3f84db92755','549c7365-28e9-491f-9040-412558f93a5c','35db7cf0-556e-49d8-b6d2-f6e1b1e12e16','6c285c60-022a-4a00-b172-87df97f16a2f','c7d438a6-34d6-423f-905d-446b839e2f39','45080597-55fa-42dc-aa65-12d7694e4b7e','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','f175019d-5a93-4cd4-aabc-e7e79445f15a','fc6e31ce-388e-45cd-956b-b238b9134eb1','286d1783-cd34-4aae-ac8b-006529ec8bc5','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"당근, 피망, 양파를 잘게 다진 뒤\r\n기름에 살짝 볶아 밥에\r\n마요네즈(10g)와 함께 넣어 섞는다.","imageUrl":null},{"step":2,"text":"통조림 연어는 기름기를 빼고,\r\n식초를 넣은 끓는 물에서 30초 정도\r\n데친다.","imageUrl":null},{"step":3,"text":"데리야키소스와 마요네즈(10g)에\r\n연어를 넣고 버무려 양념한다.","imageUrl":null},{"step":4,"text":"밥을 동그랗게 빚은 뒤 가운데에\r\n연어를 넣고 주먹밥을 만든다.","imageUrl":null},{"step":5,"text":"달걀물과 빵가루를 입혀 160℃로\r\n예열한 기름에 바삭하게 튀긴다.","imageUrl":null},{"step":6,"text":"연어주먹밥튀김을 담고\r\n어린잎채소를 곁들인 뒤\r\n오리엔탈소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00228_2.png', 660.2, 25.1, 6.56, 6.75, 537.1),
  ('229', '오징어불고기김밥', '밥', ' 오징어 몸통(130g), 파프리카(30g), 당근(20g), 피망(30g), 밥(200g),썬 쇠고기(우둔살, 60g), 달걀(50g), 김(2g), 깻잎(20g), 새송이버섯(30g),참기름(15g), 고추장(3g), 매실청(15g)', '["오징어 몸통","파프리카","당근","피망","밥","썬 쇠고기","달걀","김","깻잎","새송이버섯","참기름","고추장","매실청"]'::jsonb, ARRAY['5e79d288-1400-4817-bd20-e5e6041821b1','e38c12a7-43cb-421a-a36e-7ef0d32517fa','df459e6f-3515-45d5-8c9a-9d37b6249379','ecb35816-34ae-4c4c-867a-e3f84db92755','c7d438a6-34d6-423f-905d-446b839e2f39','09229cbc-4574-4002-b726-68c37345bbe9','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','3f94371a-728f-49ae-8ea9-1a1e87b68048','0c0ade94-cfd8-4104-b44c-40e942cac482','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','02fd7135-0ec3-49ec-82e3-390536ab2cf5']::uuid[], '[{"step":1,"text":"오징어 몸통 안쪽에 칼집을 내고\r\n끓는 물에 데친다.","imageUrl":null},{"step":2,"text":"파프리카와 당근, 피망은 작게 다져\r\n볶은 뒤 밥에 넣어 섞는다.","imageUrl":null},{"step":3,"text":"쇠고기는 참기름에 볶는다.","imageUrl":null},{"step":4,"text":"달걀을 풀어 약한 불로 달군 팬에\r\n부은 뒤 김가루를 뿌려 지단을\r\n부치고, 바닥이 익으면 깻잎과\r\n밥을 올린다.","imageUrl":null},{"step":5,"text":"데친 오징어, 볶은 쇠고기 순으로\r\n올려 만 뒤 랩으로 싼다.","imageUrl":null},{"step":6,"text":"고추장과 매실청을 섞은 뒤 팬에\r\n넣고 약한 불에서 끓여 소스를\r\n만들고 한입 크기로 썬 김밥에\r\n구운 버섯을 함께 곁들여\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00229_2.png', 452.2, 14.5, 13.9, 3.42, 244.4),
  ('230', '닭가슴살청포묵비빔밥', '밥', ' 닭가슴살(40g), 양배추(10g), 청포묵(30g), 숙주(30g)
쌀(80g), 달걀지단(20g), 무순(5g),삶는 재료 된장(3g), 마늘(5g), 후춧가루(0.1g), 소금(0.1g),저염간장(4g), 참기름(1g)', '["닭가슴살","양배추","청포묵","숙주","쌀","달걀지단","무순","삶는 재료 된장","마늘","후춧가루","소금","저염간장","참기름"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','fd4254d4-2691-47e1-9367-c2b820ef8d00','6286955d-86b2-4a91-9b23-c49f388a5f45','2647e451-e8f5-4fce-91bd-8beabb2384d8','a5bc0b46-0192-496a-b429-d2cb90b2bca9','c7d438a6-34d6-423f-905d-446b839e2f39','f09d1d41-602a-441c-a7bc-520311490ceb','fc6e31ce-388e-45cd-956b-b238b9134eb1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','2cf0c12b-f248-4012-8f53-303c730a7b3d','f175019d-5a93-4cd4-aabc-e7e79445f15a','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"닭고기 삶는 재료를 물(100g)에 넣어\r\n끓이다가 닭가슴살을 넣고 삶아\r\n한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"양배추는 곱게 채 썰고, 청포묵은\r\n먹기 좋은 크기로 썬다.","imageUrl":null},{"step":3,"text":"숙주는 끓는 물에 데쳐 물기를 뺀다","imageUrl":null},{"step":4,"text":"비빔소스를 만든다.","imageUrl":null},{"step":5,"text":"쌀에 물을 붓고 밥을 짓는다.","imageUrl":null},{"step":6,"text":"밥 위에 닭가슴살, 양배추, 청포묵,\r\n숙주, 달걀지단, 무순을 담아\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00230_2.png', 421.5, 28.1, 5.19, 1.27, 104),
  ('325', '족발수육', '반찬', ' 양념족발 200g, 고구마 150g, 가지 150g, 맥주 400g, 백김치 50g
, 참기름 15g, 통깨 3g', '["양념족발","고구마","가지","맥주","백김치","참기름","통깨"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','3e12cf79-2cde-4309-9f7c-4eccce3fde28','133f214e-50f4-431d-af36-d97f6c9d4f9b','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"조미된 족발은 뜨거운 맥주에 데쳐내 기름기를\r\n제거한다.","imageUrl":null},{"step":2,"text":"고구마는 편으로 썰어 냉수에 헹궈 기름\r\n없는 팬에 구워준다.","imageUrl":null},{"step":3,"text":"가지는 편으로 썰어서 수분을 제거한다.","imageUrl":null},{"step":4,"text":"가지는 편으로 썰어 살짝 구워준다.","imageUrl":null},{"step":5,"text":"백김치는 물에 헹궈서 손으로 꼭 짠 후 송송\r\n썰어서 양념을 해 무쳐준다.","imageUrl":null},{"step":6,"text":"무쳐준 김치와 함께 구워진 채소와 족발수육을\r\n담아 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00325_2.png', 282.2, 16.2, 22.2, 14.3, 471.7),
  ('326', '함초떡갈비', '반찬', '갈은 소고기 150g, 갈은 돼지고기 150g, 당근 25g, 새송이버섯 20g
함초 30g, 양파 25g, 샐러리 10g, 대파 10g,
다진마늘 10g, 참기름 15g, 통깨 5g, 함초소금 1g
소스 : 발사믹식초 30g, 설탕 15g, 흰후추 1g', '["갈은 소고기","갈은 돼지고기","당근","새송이버섯","함초","양파","샐러리","대파","다진마늘","참기름","통깨","함초소금","소스 : 발사믹식초","설탕","흰후추"]'::jsonb, ARRAY['e38c12a7-43cb-421a-a36e-7ef0d32517fa','3f94371a-728f-49ae-8ea9-1a1e87b68048','2753a03c-9508-458a-9f55-75307de4f7d5','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','12d2d4c9-705a-47f1-b628-30e042a970f8','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d','06e6f3e7-0293-469d-a338-11a610f3e71b','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"함초는 송송 다져준다.","imageUrl":null},{"step":2,"text":"당근, 새송이, 샐러리, 양파를 송송 다져준다.","imageUrl":null},{"step":3,"text":"볼에 소고기, 돼지고기, 다져 놓은 채소와\r\n다진마늘, 다진대파, 참기름을 넣고 반죽해준다.","imageUrl":null},{"step":4,"text":"여기에 함초 다진 것을 넣고 다시 반죽해 준다.","imageUrl":null},{"step":5,"text":"떡갈비 모양으로 만들어준 후 팬에 노릇하게\r\n구워준다.","imageUrl":null},{"step":6,"text":"소스를 만들어 구워진 떡갈비를 졸여준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00326_2.png', 254.1, 5.7, 19.8, 16.9, 210.5),
  ('327', '삼색소면', '일품', '3가지색 소면(분홍, 초록, 흰색) 각 25g씩, 쪽파 20g, 청고추 20g, 홍고추 15g, 마늘 10g
국물 : 다시마물 400g, 모시조개 200g, 볶은소금 1g, 청주 15g', '["쪽파","청고추","홍고추","마늘","국물 : 다시마물","모시조개","볶은소금","청주"]'::jsonb, ARRAY['4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','b6047d76-6c94-4757-b1d1-9175aea0c84a','2cf0c12b-f248-4012-8f53-303c730a7b3d','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1']::uuid[], '[{"step":1,"text":"모시조개는 볶은소금을 넣어서 해감시킨다.","imageUrl":null},{"step":2,"text":"준비된 다시마물에 준비된 채소의 국물재료를\r\n넣고 국물을 만들어준다.","imageUrl":null},{"step":3,"text":"만들어진 국물에 모시조개를 넣고 청주를\r\n부어서 국물을 만들어준다.","imageUrl":null},{"step":4,"text":"쪽파는 송송 다지고 마늘은 곱게 다져주고\r\n청홍고추는 가늘게 채 썰어준다.","imageUrl":null},{"step":5,"text":"면을 각각 삶아준다.","imageUrl":null},{"step":6,"text":"삼색 면을 그릇에 담고 만들어진 국물을\r\n부워서 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00327_2.png', 168.1, 29.4, 8.5, 1.8, 437.6),
  ('328', '돼지수육맑은전골', '국&찌개', '통삼겹 250g, 된장 10g, 통후추 2g
다진대파 5g, 팽이버섯 10g, 당근 20g, 배추 30g, 청경채 20g
애호박 25g, 숙주 25g, 청양고추 20g
육수 : 천연다시다 15g, 물 300g, 다진마늘 5g
곁들이장 : 어간장 15g, 겨자 5g, 식초 15g, 깨 5g', '["통삼겹","된장","통후추","다진대파","팽이버섯","당근","배추","청경채","애호박","숙주","청양고추","육수 : 천연다시다","물","다진마늘","곁들이장 : 어간장","겨자","식초","깨"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','392236b1-82e9-4e38-bd12-6a53b80bf463','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','4b410642-7bf9-45ad-9055-e7d9a34edaa1','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','e38c12a7-43cb-421a-a36e-7ef0d32517fa','e116f85b-0eaa-40cb-8107-df5ec8486ad4','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','2647e451-e8f5-4fce-91bd-8beabb2384d8','30b5d53c-d247-4f04-9b50-c0f728e65cf9','94786475-832c-4f97-aab7-bf6fbbe2236b','fc6e31ce-388e-45cd-956b-b238b9134eb1','5b59cfae-1277-48af-99a6-833687e2da0b','6c285c60-022a-4a00-b172-87df97f16a2f','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"당근, 청경채, 배추, 애호박, 팽이버섯은 먹기\r\n좋은 크기로 잘라준다.","imageUrl":null},{"step":2,"text":"흑돼지고기, 저염된장, 후추를 넣어서 불순물을\r\n제거하면서 고기를 삶아준다.","imageUrl":null},{"step":3,"text":"천연다시다로 육수를 만들어 체에 걸러준다.","imageUrl":null},{"step":4,"text":"손질한 야채들과 청양고추를 잘라 함께 육수에\r\n데쳐 국물에 매운 맛을 낸다.","imageUrl":null},{"step":5,"text":"곁들이장을 만들어 준다.","imageUrl":null},{"step":6,"text":"냄비에 데쳐준 채소와 국물을 붓고 고기를\r\n먹기좋게 썰어 소스랑 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00328_2.png', 120.3, 9.6, 0.6, 8.8, 147.7),
  ('329', '채소비빔밥', '밥', '쌀 150g, 바지락 100g, 다진쇠고기 25g, 물 300g, 참기름 15g, 흰후추 1g, 다진마늘 15g
애호박 25g, 양파 25g, 오이 25g, 당근 25g, 표고 25g
두부볶음 : 두부 50g, 함초 25g, 깻잎 10g, 양파 20g, 다진파 15g, 다진마늘 15g', '["쌀","바지락","다진쇠고기","물","참기름","흰후추","다진마늘","애호박","양파","오이","당근","표고","두부볶음 : 두부","함초","깻잎","다진파"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','b6047d76-6c94-4757-b1d1-9175aea0c84a','1c49d1f4-5781-474d-818d-bd7002a4dc0b','94786475-832c-4f97-aab7-bf6fbbe2236b','0c0ade94-cfd8-4104-b44c-40e942cac482','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','fc6e31ce-388e-45cd-956b-b238b9134eb1','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','e38c12a7-43cb-421a-a36e-7ef0d32517fa','2753a03c-9508-458a-9f55-75307de4f7d5','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','4b410642-7bf9-45ad-9055-e7d9a34edaa1']::uuid[], '[{"step":1,"text":"바지락은 해감을 시켜준 후 물에 넣어 바지락\r\n육수를 만들어준다.","imageUrl":null},{"step":2,"text":"바지락살은 따로 떼어내어 다진소고기와\r\n다시 다져서 양념해 볶아준다.","imageUrl":null},{"step":3,"text":"두부는 물기제거를 한 후 함초, 깻잎, 다진양파,\r\n를 넣어 치대어 두부볶음을 만들어준다.","imageUrl":null},{"step":4,"text":"애호박은 채 썰어주고 양파, 오이, 당근, 표고도\r\n채 썰어 각각 볶아준다.","imageUrl":null},{"step":5,"text":"볶은 바지락과 쌀을 넣어 밥을 한다.","imageUrl":null},{"step":6,"text":"몰드에 밥과 각종 채소들을 올려주고 마지막에\r\n두부 스크램블을 올려 밥을 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00329_2.png', 303.9, 41.2, 10.4, 10.8, 189.2),
  ('330', '열무김치파스타', '일품', '파스타면 50g, 열무김치 100g, 오이 20g, 청홍고추 각각 15g
