  ('337', '근채류주먹밥', '밥', '우엉 20g, 연근 20g, 감자 20g, 청고추 10g, 양파 10g, 당근 10g
쌀 100g, 오이 70g, 통깨 1g, 맛간장 15g, 참기름 5g, 마늘기름 15g, 함초소금 2g', '["우엉","연근","감자","청고추","양파","당근","쌀","오이","통깨","맛간장","참기름","마늘기름","함초소금"]'::jsonb, ARRAY['6b3a8bca-adc3-48f5-813b-6b06630e11dd','b20f623d-e722-42af-9bd1-7c11b5e15aa6','20894da1-739d-4d52-b5fe-4943bd3492d5','30b5d53c-d247-4f04-9b50-c0f728e65cf9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','a5bc0b46-0192-496a-b429-d2cb90b2bca9','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','f175019d-5a93-4cd4-aabc-e7e79445f15a','0c0ade94-cfd8-4104-b44c-40e942cac482','34302eb3-407c-41e6-b9ae-89f6123f4b65','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"쌀을 깨끗하게 씻은 후에 쌀뜨물은 따로\r\n보관하고 불려준 쌀로 밥을 해주고 접시에\r\n펼쳐 식혀준다.","imageUrl":null},{"step":2,"text":"우엉과 연근, 감자는 송송 다져준 후 아린 맛을\r\n빼기위해 물에 담가준다.","imageUrl":null},{"step":3,"text":"우엉과 연근, 감자는 물기를 빼고 볶아준다.","imageUrl":null},{"step":4,"text":"청고추, 양파, 당근은 송송 다져서 함께\r\n볶아준 뒤, 함초 소금을 이용해 1차 간을\r\n해준다.","imageUrl":null},{"step":5,"text":"그 릇 에 모 든 재 료 를 넣 고 오 니 기 리 를\r\n만들어준다.","imageUrl":null},{"step":6,"text":"그릇에 담아 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00337_2.png', 117.3, 25.2, 2.4, 0.8, 11.3),
  ('338', '단호박약식', '밥', '미니 단호박 250g, 찹쌀 100g, 밤 40g, 대추 18g, 크린베리 10g
