소스 : 저염간장 15g, 유자청 30g, 다진청고추 7g, 다진홍고추 7g, 다진대파 7g', '["두가지 묵 각","당귀잎","양파","노란 파프리카","알배추","소스 : 저염간장","유자청","다진청고추","다진홍고추","다진대파"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e116f85b-0eaa-40cb-8107-df5ec8486ad4','ff5b6cbe-7985-4ca2-94ad-5525717cddf1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1']::uuid[], '[{"step":1,"text":"당귀는 잎만 떼어 먹기 좋게 잘라서 물에\r\n담가준다.","imageUrl":null},{"step":2,"text":"두가지묵은 먹기 좋게 길이로 잘라준다.","imageUrl":null},{"step":3,"text":"양파, 파프리카, 알배추는 가늘게 채 썰어준다.","imageUrl":null},{"step":4,"text":"소스를 만들어준다.","imageUrl":null},{"step":5,"text":"모든 재료를 담고 소스에 통깨를 섞은 뒤\r\n샐러드에 뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00364_2.png', 53.6, 9.7, 1, 1.2, 109.2),
  ('365', '블루베리양갱', '후식', '흰앙금 100g, 블루베리 30g, 설탕 30g, 한천 20g, 물100g', '["흰앙금","블루베리","설탕","한천","물"]'::jsonb, ARRAY['203b7165-14df-4cb6-b165-e4dadf9a3079','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"블루베리는 믹서에 갈아서 체에 내려준다.","imageUrl":null},{"step":2,"text":"물에 끓여주면서 흰앙금과 설탕을 풀어준다.","imageUrl":null},{"step":3,"text":"여기에 다시 한천가루를 넣어 끓여준다.","imageUrl":null},{"step":4,"text":"여기에 블루베리를 넣어 끓인다.","imageUrl":null},{"step":5,"text":"몰드에 넣어서 시원한 곳에서 식혀준다.","imageUrl":null},{"step":6,"text":"접시에 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00365_2.png', 142.4, 20.3, 8, 3.3, 32.2),
